item.content:encoded:
@media (min-width: 1200px) and (max-width: 1480px) {
	.tp-choose-image-shapes {
		img {
			width: 590px !important;
		}
	}
}



@media (min-width: 1479px) and (max-width: 1780px) {
	.tp-choose-image-shapes {
		img {
			width: 790px !important;
		}
	}
}

@media only screen and (min-width: 1600px) and (max-width: 1700px) {
  .custome_light_image  img {
    max-width: 50%;
  }
}

@media screen and (max-width: 1600px) {
  .custome_light_image div img {
    display: none;
  }
}


@media screen and (max-width: 1399px) {
  .custome_cable_image div span {
    display: none !important;
  }
}

@media (max-width: 577px) {
	.tp-gallery-img .gallery-item {
		width: auto;
	}
}
.search__wrapper .search__logo img {
	width: 150px;
}

.search__popup {
	height: auto;
}
.tp-service-7-thumb img {
	border-radius: 20px !important;
}

.tp-project-7-thumb img {
	border-radius: 20px !important;
}
ul {
	list-style: none !important;
}

.tp-header-7-main-menu nav ul li > a.active {
	color: var(--tp-theme-3);
}

.comeing-soon .homemenu-thumb::before {
  position: absolute;
  z-index: 22;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  content: "";
  backdrop-filter: blur(6px);
  background-color: rgba(0, 0, 0, 0.2);
}

